import React, { useContext, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import DoctorCard from "../components/DoctorCard";
import { AuthContext } from "../context/AuthContext";
import { appointmentAPI, authAPI, doctorAPI } from "../services/api";
import { getErrorMessage } from "../utils/helpers";
import "./DashboardPages.css";

const PatientPage = ({ showToast }) => {
  const [doctors, setDoctors] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [activeTab, setActiveTab] = useState("doctors");
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const formatDate = (value) => {
    if (!value) return "N/A";
    return new Date(value).toLocaleDateString();
  };

  useEffect(() => {
    doctorAPI.getAll().then(setDoctors).catch((e) => showToast(getErrorMessage(e), "error"));
    appointmentAPI.getAll().then(setAppointments).catch(() => {});
  }, []);

  const refreshAppointments = async () => {
    try {
      const data = await appointmentAPI.getAll();
      setAppointments(data);
    } catch (error) {
      showToast(getErrorMessage(error), "error");
    }
  };

  const handleBookAppointment = async (doctorId) => {
    const date = window.prompt("Enter appointment date (YYYY-MM-DD):");
    if (!date) return;

    const time = window.prompt("Enter appointment time (HH:mm:ss):", "10:00:00");
    if (!time) return;

    try {
      await appointmentAPI.book({ doctor_id: doctorId, date, time });
      showToast("Appointment booked successfully", "success");
      setActiveTab("appointments");
      refreshAppointments();
    } catch (error) {
      showToast(getErrorMessage(error), "error");
    }
  };

  const handleLogout = async () => {
    await authAPI.logout();
    logout();
    navigate("/login");
  };

  return (
    <div className="dashboard-page">
      <header className="header">
        <div className="header-content">
          <h1>Patient Dashboard</h1>
          <div className="header-right">
            <div className="user-info">Logged in as <strong>{user?.name}</strong> ({user?.role})</div>
            <button className="logout-btn" onClick={handleLogout}>Logout</button>
          </div>
        </div>
      </header>
      <div className="container">
        <div className="page-content">
          <div className="tabs">
            <button className={`tab-btn ${activeTab === "doctors" ? "active" : ""}`} onClick={() => setActiveTab("doctors")}>Find Doctors ({doctors.length})</button>
            <button className={`tab-btn ${activeTab === "appointments" ? "active" : ""}`} onClick={() => setActiveTab("appointments")}>My Appointments ({appointments.length})</button>
          </div>

          {activeTab === "doctors" ? (
            <>
              <h3 className="section-title">Find & Book Doctors</h3>
              {doctors.length ? (
                <div className="doctors-list">
                  {doctors.map((doctor) => (
                    <div key={doctor.id} className="doctor-item">
                      <DoctorCard doctor={doctor} />
                      <button className="btn-primary" onClick={() => handleBookAppointment(doctor.id)}>Book Appointment</button>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="no-data">No approved doctors available</div>
              )}
            </>
          ) : (
            <>
              <h3 className="section-title">Your Appointments</h3>
              {appointments.length ? (
                <div className="appointment-list">
                  {appointments.map((appointment) => (
                    <div key={appointment.id} className="appointment-card">
                      <div className="appointment-header">
                        <div className="appointment-date-time">
                          <div className="appointment-date">{formatDate(appointment.appointment_date)}</div>
                          <div className="appointment-time">{appointment.appointment_time || "N/A"}</div>
                        </div>
                        <span className={`status-badge status-${appointment.status || "booked"}`}>
                          {appointment.status || "booked"}
                        </span>
                      </div>

                      <div className="appointment-body">
                        <p><strong>Doctor:</strong> {appointment.doctor_name || "Doctor"}</p>
                        <p><strong>Department:</strong> {appointment.department || "N/A"}</p>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="no-data">No appointments booked yet</div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default PatientPage;
